    E.g. (()()) has maximum two levels of nesting while ((())) has three.

    >>> parse_nested_parens('(()()) ((())) () ((())()())')
    [2, 3, 1, 3]
    """
    result = []

    for group in paren_string.split(' '):
        if not group:
            continue
        depth = 0
        for char in group:
            if char == '(':
                depth += 1
            elif char == ')':
                depth -= 1
                if depth == 0:
                    result.append(depth)
        if depth == 0:
            result.append(0)

    return result

