    select_words("simple white space", 2) ==> []
    select_words("Hello world", 4) ==> ["world"]
    select_words("Uncle sam", 3) ==> ["Uncle"]
    """
    if not s:
        return []

    def count_consonants(word):
        return sum(1 for c in word if c.islower() or c.isupper())

    def get_consonant_indices(word):
        return [i for i, c in enumerate(word) if c.islower() or c.isupper()]

    def get_consonant_words(word):
        return [word[i] for i in get_consonant_indices(word)]

    def is_consonant(word):
        return all(c.islower() or c.isupper() for c in word)

    def is_consonant_word(word):
        return is_consonant(word) and len(get_consonant_indices(word)) == n

    words = []
    for word in s.split():
        if is_consonant_word(word):
            words.append(word)

    return words

def match_parens(lst):
    """
    You are given a list of two strings, both strings consist of open
    parentheses '(' or close parentheses ')' only.
    Your job is to check if it is possible to concatenate the two strings in
    some order, that the resulting string will be good.
    A string S is considered to be good if and only if all parentheses in S
    are balanced. For example: the string '(())()' is good, while the string
    '())' is not.
    Return 'Yes' if there's a way to make a good string, and return 'No' otherwise.

    Examples:
    match_parens(['()(', ')']) == 'Yes'
    match_parens([')', ')']) == 'No'
    '''
    def is_good(s):
        count = {'(': 0, ')': 0}
        for char in s:
            if char == '(':
                count['('] += 1
            else:
                count['('] -= 1
                if count['('] < 0:
                    return False
        return count['('] == 0

    def is_possible(lst):
        if len(lst) != 2:
            return False
        s1, s2 = lst
        if not is_good(s1) or not is_good(s2):
            return False
        return True

    return is_possible(lst)

